#include<bits/stdc++.h>
using namespace std;
const int MOD = 10007;
int n,m,result;
int a[50005],pre[50005],predp[50005],dp[50005],pos[50005];
bool check(int x){
	int pre = 0,counter = 0;
	for(int i = 1;i<=n;i++){
		if(a[i]>x)return false;
		if (pre+a[i]>x){
			pre = 0;
			counter++;
		}
		pre += a[i];
	}
	return (counter <= m);
}
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++){
		cin>>a[i];
		pre[i] = pre[i - 1] + a[i];
	}
	int l = 1, r = 1e9;
	while(l < r) {
		int mid = (l + r) / 2;
		if (check (mid)) {
			r = mid;
		} else {
			l = mid + 1;
		}
	}
	for (int i = 1; i <= n; i++){
		if (pre[i] <= l){
			dp[i] = 1;
		}
		predp[i] += predp[i-1] + dp[i]; 
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 0; j < i; j++) {
			if (pre[i] - pre[j] <= l) {
				pos[i] = j;
				break; 
			}
		}
	}
	for (int j = 2; j <= m + 1; j++) {
		for (int i = 1; i <= n; i++) {
			dp[i] = predp[i - 1];
			if (pos[i] >= 1) {
				dp[i] = (dp[i] - predp[pos[i] - 1] + MOD) % MOD;
			}
		}
		predp[0] = 0;
		for(int i = 1;i<=n;i++){
			predp[i] = (predp[i - 1] + dp[i]) % MOD;
		}
		result = (result + dp[n]) % MOD;
	}
	if (pre[n] <= l) {
		result++;
	}
	cout << l << ' ' << result;
	return 0;
}
